/* ─── LERP ─── */
function lerp(a: number, b: number, t: number) { return a + (b - a) * t; }

/* ─── WAVE BAR ─── */
function WaveBar({ values, active }: { values: number[]; active: boolean }) {
  return (
    <div style={{ display:'flex', alignItems:'center', gap:3, height:44 }}>
      {values.map((v,i) => (
        <div key={i} style={{
          width:4, borderRadius:2,
          height: active ? `${v*100}%` : '15%',
          background:'#111',
          opacity: active ? 0.4 + v*0.6 : 0.1,
          transition:`height ${0.25+i*0.04}s cubic-bezier(.34,1.56,.64,1) ${active?i*0.03:0}s`,
        }}/>
      ))}
    </div>
  );
}

/* ─── TILT CARD ─── */
function TiltCard({ children, style, onClick }: { children: React.ReactNode; style?: React.CSSProperties; onClick?: () => void }) {
  const ref = useRef<HTMLDivElement>(null);
  const [tilt, setTilt] = useState({ rx:0, ry:0, gx:50, gy:50, scale:1 });
  return (
    <div ref={ref} onClick={onClick}
      onMouseMove={e => {
        const r = ref.current!.getBoundingClientRect();
        const x = (e.clientX-r.left)/r.width, y = (e.clientY-r.top)/r.height;
        setTilt({ rx:(y-.5)*16, ry:(x-.5)*-16, gx:x*100, gy:y*100, scale:1.025 });
      }}
      onMouseLeave={() => setTilt({ rx:0, ry:0, gx:50, gy:50, scale:1 })}
      style={{
        transform:`perspective(700px) rotateX(${tilt.rx}deg) rotateY(${tilt.ry}deg) scale(${tilt.scale})`,
        transition:'transform .13s linear',
        transformStyle:'preserve-3d',
        position:'relative',
        ...style,
      }}
    >
      <div style={{ position:'absolute', inset:0, borderRadius:'inherit', pointerEvents:'none', zIndex:3,
        background:`radial-gradient(circle at ${tilt.gx}% ${tilt.gy}%, rgba(0,0,0,.06) 0%, transparent 60%)`,
        transition:'background .13s linear',
      }}/>
      <div style={{ position:'absolute', inset:0, borderRadius:'inherit', pointerEvents:'none', zIndex:0,
        boxShadow:`0 ${16+tilt.rx*1.5}px ${48+Math.abs(tilt.rx)*2}px rgba(0,0,0,${.08+Math.abs(tilt.rx)*.005})`,
        transition:'box-shadow .13s linear',
      }}/>
      <div style={{ position:'relative', zIndex:2 }}>{children}</div>
    </div>
  );
}

