          {['20Hz','50Hz','125Hz','250Hz','500Hz','1kHz','2kHz','4kHz','8kHz','12kHz','16kHz','20kHz'].map(f=>(
            <span key={f} style={{ fontFamily:"'JetBrains Mono',monospace", fontSize:6, color:'#ccc', letterSpacing:1 }}>{f}</span>
          ))}
