/* ─── 360° ROTATABLE HEADSET ─── */
function RotatableHeadset({ explode, autoX, autoY }: { explode: number; autoX: number; autoY: number }) {
  const [rotY, setRotY] = useState(15);
  const [rotX, setRotX] = useState(-8);
  const drag = useRef({ on:false, sx:0, sy:0, startRotY:15, startRotX:-8, vx:0, vy:0, lastDx:0, lastDy:0 });
  const rafRef = useRef<number>(0);
  const containerRef = useRef<HTMLDivElement>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [isHover, setIsHover] = useState(false);

  useEffect(() => {
    const onMove = (e: MouseEvent | TouchEvent) => {
      if (!drag.current.on) return;
      const cx = 'touches' in e ? e.touches[0].clientX : e.clientX;
      const cy = 'touches' in e ? e.touches[0].clientY : e.clientY;
      const dx = cx - drag.current.sx;
      const dy = cy - drag.current.sy;
      drag.current.vx = dx - drag.current.lastDx;
      drag.current.vy = dy - drag.current.lastDy;
      drag.current.lastDx = dx;
      drag.current.lastDy = dy;
      setRotY(drag.current.startRotY + dx * 0.5);
      setRotX(drag.current.startRotX + dy * 0.35);
    };
    const onUp = () => {
      if (!drag.current.on) return;
      drag.current.on = false;
      setIsDragging(false);
      const vx = drag.current.vx;
      const vy = drag.current.vy;
      let cvx = vx, cvy = vy;
      const spin = () => {
        cvx *= 0.92; cvy *= 0.92;
        if (Math.abs(cvx) < 0.05 && Math.abs(cvy) < 0.05) return;
        setRotY(r => r + cvx * 0.4);
        setRotX(r => r + cvy * 0.28);
        rafRef.current = requestAnimationFrame(spin);
      };
      rafRef.current = requestAnimationFrame(spin);
    };
    window.addEventListener('mousemove', onMove);
    window.addEventListener('mouseup', onUp);
    window.addEventListener('touchmove', onMove as EventListener, { passive: true });
    window.addEventListener('touchend', onUp);
    return () => {
      window.removeEventListener('mousemove', onMove);
      window.removeEventListener('mouseup', onUp);
      window.removeEventListener('touchmove', onMove as EventListener);
      window.removeEventListener('touchend', onUp);
      cancelAnimationFrame(rafRef.current);
    };
  }, []);

  const startDrag = (cx: number, cy: number) => {
    cancelAnimationFrame(rafRef.current);
    drag.current = { on:true, sx:cx, sy:cy, startRotY:rotY, startRotX:rotX, vx:0, vy:0, lastDx:0, lastDy:0 };
    setIsDragging(true);
  };

  const finalRotY = isDragging ? rotY : rotY + autoX * 12;
  const finalRotX = isDragging ? rotX : rotX + autoY * 6;

  return (
    <div ref={containerRef}
      style={{ position:'relative', width:400, height:420, display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0, cursor: isDragging?'grabbing':isHover?'grab':'default', userSelect:'none' }}
      onMouseEnter={() => setIsHover(true)}
      onMouseLeave={() => setIsHover(false)}
      onMouseDown={e => startDrag(e.clientX, e.clientY)}
      onTouchStart={e => startDrag(e.touches[0].clientX, e.touches[0].clientY)}
    >
      {/* subtle orbit rings */}
      {[300, 360, 420].map((r,i) => (
        <div key={i} style={{ position:'absolute', width:r, height:r, border:`1px solid rgba(0,0,0,${0.04-i*0.01})`, borderRadius:'50%', transform:`rotateX(72deg) rotateZ(${i*50}deg)`, pointerEvents:'none' }}/>
      ))}
      {/* orbit dots */}
      {[{ r:290,dur:'9s',d:'0s'},{r:352,dur:'14s',d:'3s'}].map((o,i) => (
        <div key={i} style={{ position:'absolute', width:o.r, height:o.r, animation:`orbitDark${i} ${o.dur} linear infinite`, animationDelay:o.d, borderRadius:'50%', opacity:.3, pointerEvents:'none' }}>
          <div style={{ width:4, height:4, borderRadius:'50%', background:'#000', position:'absolute', top:0, left:'50%', marginLeft:-2, boxShadow:'0 0 6px rgba(0,0,0,.3)' }}/>
        </div>
      ))}

      {/* spotlight on white bg */}
      <div style={{ position:'absolute', width:380, height:380,
        background:`radial-gradient(circle at ${50+autoX*20}% ${50+autoY*20}%,rgba(0,0,0,.04) 0%,transparent 65%)`,
        borderRadius:'50%', pointerEvents:'none', transition:'background .08s linear',
      }}/>

      {/* ground shadow */}
      <div style={{ position:'absolute', bottom:0, left:'50%', transform:'translateX(-50%)', width:280, height:20, background:'radial-gradient(ellipse,rgba(0,0,0,.12) 0%,transparent 70%)', filter:'blur(8px)', pointerEvents:'none' }}/>

      {/* ── THE 3D HEADSET (both images layer, crossfade on scroll) ── */}
      <div style={{
        position:'relative', width:340, height:340,
        /* This is the actual 360° rotation */
        transform:`perspective(1100px) rotateY(${finalRotY}deg) rotateX(${finalRotX}deg)`,
        transformStyle:'preserve-3d',
        transition: isDragging ? 'none' : 'transform .07s linear',
        willChange:'transform',
      }}>
        {/* FRONT FACE — assembled photo */}
        <img src={IMG_ASSEMBLED} alt="EYT Pro X Assembled"
          style={{
            position:'absolute', inset:0, width:'100%', height:'100%', objectFit:'contain',
            opacity: 1 - explode,
            filter:'drop-shadow(0 30px 50px rgba(0,0,0,.18)) drop-shadow(0 8px 16px rgba(0,0,0,.1))',
            transition:'opacity .12s linear',
            userSelect:'none', pointerEvents:'none', backfaceVisibility:'hidden',
          }}
        />
        {/* BACK FACE — exploded diagram (inverted back to dark on white) */}
        <img src={IMG_EXPLODED} alt="EYT Pro X Exploded"
          style={{
            position:'absolute', inset:0, width:'100%', height:'100%', objectFit:'contain',
            opacity: explode,
            filter:`brightness(0.15) contrast(1.4) drop-shadow(0 10px 30px rgba(0,0,0,${.12*explode}))`,
            transform:`scale(${1 + explode * .18})`,
            transition:'opacity .12s linear',
            userSelect:'none', pointerEvents:'none',
          }}
        />

        {/* CSS 3-D depth plates — give the headset real thickness as you rotate */}
        <div style={{ position:'absolute', inset:0, transformStyle:'preserve-3d', pointerEvents:'none' }}>
          <div style={{ position:'absolute', left:-10, top:'26%', width:18, height:'48%', background:'linear-gradient(180deg,#e8e8e8,#d0d0d0)', transform:'rotateY(-90deg) translateZ(9px)', borderRadius:'4px 0 0 4px', boxShadow:'inset -2px 0 6px rgba(0,0,0,.1)' }}/>
          <div style={{ position:'absolute', right:-10, top:'26%', width:18, height:'48%', background:'linear-gradient(180deg,#e8e8e8,#d0d0d0)', transform:'rotateY(90deg) translateZ(9px)', borderRadius:'0 4px 4px 0', boxShadow:'inset 2px 0 6px rgba(0,0,0,.1)' }}/>
          <div style={{ position:'absolute', top:-8, left:'20%', width:'60%', height:14, background:'linear-gradient(90deg,#ddd,#ebebeb,#ddd)', transform:'rotateX(90deg) translateZ(7px)', boxShadow:'inset 0 2px 4px rgba(0,0,0,.08)' }}/>
          <div style={{ position:'absolute', bottom:-8, left:'20%', width:'60%', height:14, background:'linear-gradient(90deg,#ddd,#ebebeb,#ddd)', transform:'rotateX(-90deg) translateZ(7px)' }}/>
        </div>
      </div>

      {/* drag hint */}
      {!isDragging && isHover && (
        <div style={{ position:'absolute', bottom:-46, left:'50%', transform:'translateX(-50%)', fontFamily:"'JetBrains Mono',monospace", fontSize:8, color:'#bbb', letterSpacing:3, textTransform:'uppercase', whiteSpace:'nowrap', pointerEvents:'none' }}>
          ⟵ drag · rotate 360° ⟶
        </div>
      )}
      {explode > .05 && (
        <div style={{ position:'absolute', bottom: isHover?-64:-46, left:'50%', transform:'translateX(-50%)', fontFamily:"'JetBrains Mono',monospace", fontSize:8, color:'#ccc', letterSpacing:3, textTransform:'uppercase', whiteSpace:'nowrap', pointerEvents:'none' }}>
          Exploded View · {Math.round(explode*100)}%
        </div>
      )}
    </div>
  );
}

/* ─── PARTICLES (light on white bg) ─── */
function Particles() {
  const pts = useRef([...Array(35)].map((_,i) => ({ x:Math.random()*100, y:Math.random()*100, s:Math.random()*2+.4, o:Math.random()*.1+.03, sp:Math.random()*.4+.1, d:i%3 })));
  return (
    <div style={{ position:'fixed', inset:0, pointerEvents:'none', zIndex:0, overflow:'hidden' }}>
      {pts.current.map((p,i) => (
        <div key={i} style={{ position:'absolute', left:`${p.x}%`, top:`${p.y}%`, width:p.s, height:p.s, borderRadius:'50%', background:'#000', opacity:p.o, animation:`float${p.d} ${9+p.sp*10}s ease-in-out infinite`, animationDelay:`${i*.18}s` }}/>
      ))}
    </div>
  );
}

/* ─── MAIN PAGE ─── */
export default function EYTHeadsetPage() {
  const [mouseX, setMouseX] = useState(0);
  const [mouseY, setMouseY] = useState(0);
  const [scrollY, setScrollY] = useState(0);
  const [activeSec, setActiveSec] = useState<string|null>(null);
  const [featVis, setFeatVis] = useState(false);
  const [sndVis,  setSndVis]  = useState(false);
  const featRef = useRef<HTMLDivElement>(null);
  const sndRef  = useRef<HTMLDivElement>(null);
  const animRef = useRef<number>(0);
  const tMouse  = useRef({ x:0, y:0 });
  const cMouse  = useRef({ x:0, y:0 });
  const smooth  = useRef(0);
  const tScroll = useRef(0);

  useEffect(() => {
    const onS = () => { tScroll.current = window.scrollY; };
    window.addEventListener('scroll', onS, { passive:true });
    const tick = () => { smooth.current += (tScroll.current - smooth.current) * .045; setScrollY(smooth.current); requestAnimationFrame(tick); };
    requestAnimationFrame(tick);
    return () => window.removeEventListener('scroll', onS);
  }, []);

  useEffect(() => {
    const onM = (e: MouseEvent) => { const cx=window.innerWidth/2, cy=window.innerHeight/2; tMouse.current={x:(e.clientX-cx)/cx, y:(e.clientY-cy)/cy}; };
    window.addEventListener('mousemove', onM);
    const anim = () => { cMouse.current.x=lerp(cMouse.current.x,tMouse.current.x,.05); cMouse.current.y=lerp(cMouse.current.y,tMouse.current.y,.05); setMouseX(cMouse.current.x); setMouseY(cMouse.current.y); animRef.current=requestAnimationFrame(anim); };
    animRef.current = requestAnimationFrame(anim);
    return () => { window.removeEventListener('mousemove', onM); cancelAnimationFrame(animRef.current); };
  }, []);

  useEffect(() => {
    const makeObs = (el: HTMLElement|null, cb: (v:boolean)=>void) => {
      if (!el) return null;
      const o = new IntersectionObserver(([e]) => cb(e.isIntersecting), { threshold:.08 });
      o.observe(el); return o;
    };
    const o1 = makeObs(featRef.current, setFeatVis);
    const o2 = makeObs(sndRef.current,  setSndVis);
    return () => { o1?.disconnect(); o2?.disconnect(); };
  }, [activeSec]);

  const explode    = Math.min(1, Math.max(0, (smooth.current - 200) / 700));
  const scrollHint = Math.max(0, 1 - smooth.current / 200);

  const goTo = (sec: string) => {
    setActiveSec(sec);
    setTimeout(() => { const el = sec==='sound'?sndRef.current:featRef.current; el?.scrollIntoView({ behavior:'smooth', block:'start' }); }, 80);
  };
  const goBuy = () => document.getElementById('buy-sec')?.scrollIntoView({ behavior:'smooth' });

  return (
    <div style={{ background:'#fff', minHeight:'440vh', overflowX:'hidden' }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Bebas+Neue&family=DM+Serif+Display:ital@0;1&family=JetBrains+Mono:wght@300;400&display=swap');
        *{margin:0;padding:0;box-sizing:border-box;}
        html{scroll-behavior:smooth;}
        ::-webkit-scrollbar{width:2px;}
        ::-webkit-scrollbar-track{background:#f5f5f5;}
        ::-webkit-scrollbar-thumb{background:#ccc;}

        @keyframes float0{0%,100%{transform:translateY(0)}50%{transform:translateY(-18px)}}
        @keyframes float1{0%,100%{transform:translateY(0)}50%{transform:translateY(-28px)}}
        @keyframes float2{0%,100%{transform:translateY(0)}50%{transform:translateY(-12px)}}
        @keyframes fadeUp{from{opacity:0;transform:translateY(28px)}to{opacity:1;transform:translateY(0)}}
        @keyframes shimmer{0%,100%{opacity:.15}50%{opacity:.5}}
        @keyframes pulsering{0%,100%{transform:translate(-50%,-50%) scale(1);opacity:.05}50%{transform:translate(-50%,-50%) scale(1.05);opacity:.1}}
        @keyframes orbitDark0{from{transform:rotate(0deg)   translateX(145px) rotate(0deg)}   to{transform:rotate(360deg)   translateX(145px) rotate(-360deg)}}
        @keyframes orbitDark1{from{transform:rotate(180deg) translateX(176px) rotate(-180deg)} to{transform:rotate(540deg)  translateX(176px) rotate(-540deg)}}

        .nav-item{font-family:'JetBrains Mono',monospace;font-size:10px;letter-spacing:3px;color:#bbb;text-transform:uppercase;cursor:pointer;transition:color .25s;}
        .nav-item:hover,.nav-item.on{color:#000;}
        .cta-main{font-family:'JetBrains Mono',monospace;font-size:10px;letter-spacing:4px;text-transform:uppercase;background:#000;border:1px solid #000;color:#fff;padding:15px 32px;cursor:pointer;position:relative;overflow:hidden;transition:all .3s;}
        .cta-main::before{content:'';position:absolute;inset:0;background:#fff;transform:translateX(-101%);transition:transform .3s;}
        .cta-main:hover::before{transform:translateX(0);}
        .cta-main:hover{color:#000;}
        .cta-main span{position:relative;z-index:1;}
        .cta-ghost{font-family:'JetBrains Mono',monospace;font-size:10px;letter-spacing:4px;text-transform:uppercase;background:transparent;border:1px solid #ddd;color:#aaa;padding:15px 32px;cursor:pointer;transition:all .3s;}
        .cta-ghost:hover{border-color:#888;color:#333;}
        .spec-row{display:flex;justify-content:space-between;align-items:center;padding:13px 0;border-bottom:1px solid rgba(0,0,0,.06);font-family:'JetBrains Mono',monospace;font-size:11px;}
        .spec-label{color:#ccc;letter-spacing:2px;text-transform:uppercase;}
        .spec-val{color:#333;}
        .grid-bg{background-image:linear-gradient(rgba(0,0,0,.03) 1px,transparent 1px),linear-gradient(90deg,rgba(0,0,0,.03) 1px,transparent 1px);background-size:64px 64px;}
        .arch-row{display:flex;align-items:center;gap:10px;padding:11px 14px;border-left:2px solid #eee;background:rgba(0,0,0,.015);border-radius:0 3px 3px 0;cursor:pointer;transition:border-left-color .2s,background .2s,transform .2s;}
        .arch-row:hover{border-left-color:#333;background:rgba(0,0,0,.04);transform:translateX(4px);}
      `}</style>

      <Particles/>

      {/* subtle grid overlay */}
      <div style={{ position:'fixed', inset:0, pointerEvents:'none', zIndex:1,
        backgroundImage:'linear-gradient(rgba(0,0,0,.02) 1px,transparent 1px),linear-gradient(90deg,rgba(0,0,0,.02) 1px,transparent 1px)',
        backgroundSize:'64px 64px',
      }}/>

      {/* ══ NAV ══ */}
      <nav style={{ position:'fixed', top:0, left:0, right:0, zIndex:200, padding:'20px 52px', display:'flex', alignItems:'center', justifyContent:'space-between', background:'rgba(255,255,255,.94)', backdropFilter:'blur(20px)', borderBottom:'1px solid rgba(0,0,0,.06)' }}>
        <div style={{ display:'flex', alignItems:'center', gap:12 }}>
          <div style={{ width:26, height:26, border:'1px solid #ddd', display:'flex', alignItems:'center', justifyContent:'center' }}>
            <div style={{ width:11, height:1.5, background:'#000' }}/>
          </div>
          <span style={{ fontFamily:"'Bebas Neue',sans-serif", fontSize:20, color:'#000', letterSpacing:5 }}>EYT</span>
          <span style={{ fontFamily:"'JetBrains Mono',monospace", fontSize:7, color:'#bbb', letterSpacing:2, marginTop:2 }}>WIRELESS</span>
        </div>
        <div style={{ display:'flex', gap:40 }}>
          <span className={`nav-item${activeSec==='sound'?' on':''}`}    onClick={() => goTo('sound')}>Sound</span>
          <span className="nav-item" onClick={() => window.scrollTo({ top:0, behavior:'smooth' })}>Design</span>
          <span className={`nav-item${activeSec==='features'?' on':''}`} onClick={() => goTo('features')}>Features</span>
          <span className="nav-item" onClick={goBuy}>Buy</span>
        </div>
        <div style={{ width:6, height:6, borderRadius:'50%', background:'#000', animation:'shimmer 2.5s ease-in-out infinite' }}/>
      </nav>

      {/* ══ HERO sticky ══ */}
      <div style={{ height:'340vh', position:'relative' }}>
        <div style={{ position:'sticky', top:0, height:'100vh', display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center', overflow:'hidden', background:'#fff' }}>
          {/* pulsing ring */}
          <div style={{ position:'absolute', width:540, height:540, border:'1px solid rgba(0,0,0,.05)', borderRadius:'50%', top:'50%', left:'50%', animation:'pulsering 4s ease-in-out infinite', pointerEvents:'none' }}/>

          <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', width:'100%', maxWidth:1200, padding:'0 52px', gap:40, position:'relative', zIndex:5 }}>

            {/* LEFT */}
            <div style={{ flex:1, maxWidth:440, animation:'fadeUp .9s ease forwards' }}>
              <div style={{ fontFamily:"'JetBrains Mono',monospace", fontSize:8, letterSpacing:5, color:'#bbb', marginBottom:18, textTransform:'uppercase', display:'flex', alignItems:'center', gap:8 }}>
                <div style={{ width:20, height:1, background:'#ddd' }}/> EYT Pro X Wireless — 2026
              </div>
              <h1 style={{ fontFamily:"'Bebas Neue',sans-serif", fontSize:'clamp(50px,6.5vw,86px)', lineHeight:.9, color:'#000', marginBottom:20, letterSpacing:2 }}>
                HEAR<br/><span style={{ color:'#ccc' }}>EVERY</span><br/>DIMENSION
              </h1>
              <p style={{ fontFamily:"'DM Serif Display',serif", fontSize:14, color:'#aaa', lineHeight:1.9, marginBottom:32, fontStyle:'italic' }}>
                80 hours of Hi-Res Audio. Hybrid ANC that silences the world. Neural spatial sound that places you inside the music.
              </p>
              <div style={{ display:'flex', gap:12, flexWrap:'wrap', marginBottom:40 }}>
                <button className="cta-main" onClick={goBuy}><span>Order Now — $349</span></button>
                <button className="cta-ghost" onClick={() => goTo('sound')}>Explore Sound</button>
              </div>
              <div style={{ borderTop:'1px solid rgba(0,0,0,.06)', paddingTop:22 }}>
                {[['Frequency','5Hz – 40kHz'],['Battery','80Hr · Fast Charge'],['Codec','LDAC · aptX Lossless']].map(([l,v]) => (
                  <div key={l} className="spec-row"><span className="spec-label">{l}</span><span className="spec-val">{v}</span></div>
                ))}
              </div>
            </div>

            {/* CENTER — 360° rotatable headset */}
            <RotatableHeadset explode={explode} autoX={mouseX} autoY={mouseY}/>

            {/* RIGHT */}
            <div style={{ flex:1, maxWidth:270, display:'flex', flexDirection:'column', gap:14, animation:'fadeUp .9s .28s ease both' }}>
              <div style={{ fontFamily:"'JetBrains Mono',monospace", fontSize:8, letterSpacing:5, color:'#ccc', textTransform:'uppercase', marginBottom:4, display:'flex', alignItems:'center', gap:8 }}>
                <div style={{ width:14, height:1, background:'#ddd' }}/> Architecture
              </div>
              {FEATURES.slice(0,4).map((f,i) => (
                <div key={f.id} className="arch-row" onClick={() => goTo('features')} style={{ animation:`fadeUp .8s ${.38+i*.1}s ease both` }}>
                  <span style={{ fontSize:17, color:'#999' }}>{f.icon}</span>
                  <div style={{ fontSize:8, color:'#bbb', fontFamily:"'JetBrains Mono',monospace", letterSpacing:2, textTransform:'uppercase' }}>{f.label}</div>
                </div>
              ))}
              <TiltCard style={{ marginTop:8, padding:18, border:'1px solid rgba(0,0,0,.06)', borderRadius:3, background:'#fafafa' }}>
                <div style={{ fontFamily:"'JetBrains Mono',monospace", fontSize:7, color:'#ccc', letterSpacing:3, marginBottom:6, textTransform:'uppercase' }}>Weight</div>
                <div style={{ fontSize:44, fontFamily:"'Bebas Neue',sans-serif", color:'#000', letterSpacing:2, lineHeight:1 }}>280<span style={{ fontSize:18, color:'#ccc' }}>g</span></div>
                <div style={{ fontFamily:"'JetBrains Mono',monospace", fontSize:7, color:'#ccc', marginTop:3 }}>Titanium Frame · Featherlight</div>
              </TiltCard>
            </div>
          </div>

          {/* scroll hint */}
          <div style={{ position:'absolute', bottom:36, left:'50%', transform:'translateX(-50%)', opacity:scrollHint, transition:'opacity .3s', display:'flex', flexDirection:'column', alignItems:'center', gap:6 }}>
            <div style={{ fontFamily:"'JetBrains Mono',monospace", fontSize:7, color:'#ccc', letterSpacing:4, textTransform:'uppercase' }}>Scroll to Disassemble</div>
            <div style={{ width:1, height:32, background:'linear-gradient(180deg,#000,transparent)', animation:'float0 2s ease-in-out infinite' }}/>
          </div>

          {/* disassembly bar */}
          {explode > .01 && (
            <div style={{ position:'absolute', left:38, top:'50%', transform:'translateY(-50%)', display:'flex', flexDirection:'column', alignItems:'center', gap:4 }}>
              <div style={{ fontFamily:"'JetBrains Mono',monospace", fontSize:7, color:'#ddd', letterSpacing:2, writingMode:'vertical-rl', textTransform:'uppercase', marginBottom:4 }}>Disassembly</div>
              <div style={{ width:1.5, height:100, background:'#eee', borderRadius:2, position:'relative', overflow:'hidden' }}>
                <div style={{ position:'absolute', bottom:0, width:'100%', height:`${explode*100}%`, background:'linear-gradient(180deg,#000,#888)', transition:'height .1s' }}/>
              </div>
              <div style={{ fontFamily:"'JetBrains Mono',monospace", fontSize:7, color:'#bbb' }}>{Math.round(explode*100)}%</div>
            </div>
          )}
        </div>
      </div>

      {/* ══ SOUND ══ */}
      <div ref={sndRef} style={{ background:'#fafafa', scrollMarginTop:80 }}>
        <SoundSection visible={sndVis || activeSec==='sound'}/>
      </div>

      {/* ══ FEATURES ══ */}
      <div ref={featRef} style={{ padding:'120px 52px', maxWidth:1200, margin:'0 auto', scrollMarginTop:80 }}>
        <div style={{ textAlign:'center', marginBottom:64 }}>
          <div style={{ fontFamily:"'JetBrains Mono',monospace", fontSize:9, letterSpacing:6, color:'#ccc', textTransform:'uppercase', marginBottom:14 }}>◈ Full Feature Breakdown</div>
          <h2 style={{ fontFamily:"'Bebas Neue',sans-serif", fontSize:'clamp(42px,5.5vw,74px)', color:'#000', letterSpacing:3, lineHeight:1 }}>
            ENGINEERED FOR<br/><span style={{ color:'#e0e0e0' }}>THE OBSESSIVE</span>
          </h2>
          <p style={{ fontFamily:"'DM Serif Display',serif", fontSize:13, color:'#bbb', marginTop:14, fontStyle:'italic' }}>Hover each card — feel the depth</p>
        </div>
        <div style={{ display:'grid', gridTemplateColumns:'repeat(auto-fit,minmax(295px,1fr))', gap:18 }}>
          {FEATURES.map((f,i) => <FeatureCard key={f.id} feature={f} index={i} visible={featVis||activeSec==='features'}/>)}
        </div>
        {/* stat strip */}
        <div style={{ marginTop:64, display:'grid', gridTemplateColumns:'repeat(4,1fr)', gap:1, background:'#f0f0f0', borderRadius:3, overflow:'hidden' }}>
          {[['80','Hr','Battery'],['45','dB','ANC'],['40','mm','Driver'],['30','m','Range']].map(([v,u,l],i) => (
            <TiltCard key={i} style={{ padding:'34px 26px', background:'#fff', borderTop:`2px solid rgba(0,0,0,${.12-i*.02})`, textAlign:'center' }}>
              <div style={{ fontFamily:"'Bebas Neue',sans-serif", fontSize:56, color:'#000', letterSpacing:2, lineHeight:1 }}>{v}<span style={{ fontSize:22, color:'#ccc' }}>{u}</span></div>
              <div style={{ fontFamily:"'JetBrains Mono',monospace", fontSize:8, color:'#ccc', letterSpacing:3, textTransform:'uppercase', marginTop:5 }}>{l}</div>
            </TiltCard>
          ))}
        </div>
      </div>

      {/* ══ SPECS + BUY ══ */}
      <div id="buy-sec" style={{ padding:'80px 52px', maxWidth:1200, margin:'0 auto', scrollMarginTop:80 }} className="grid-bg">
        <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:80 }}>
          <div>
            <div style={{ fontFamily:"'JetBrains Mono',monospace", fontSize:8, color:'#bbb', letterSpacing:5, textTransform:'uppercase', marginBottom:26 }}>◉ Technical Specifications</div>
            {[['Transducer','40mm Neodymium, Closed-back'],['Frequency','5Hz – 40kHz'],['Impedance','32Ω ± 15%'],['SPL','108dB ± 3dB'],['THD','< 0.1% @ 1kHz'],['Connectivity','BT 5.4 / USB-C / 3.5mm'],['Codec','SBC, AAC, LDAC, aptX Lossless'],['Battery','1500mAh Li-Po'],['Charge','10min = 8hr (USB-C PD)'],['Weight','280g']].map(([l,v]) => (
              <div key={l} className="spec-row"><span className="spec-label">{l}</span><span className="spec-val">{v}</span></div>
            ))}
          </div>
          <div>
            <div style={{ fontFamily:"'JetBrains Mono',monospace", fontSize:8, color:'#ccc', letterSpacing:5, textTransform:'uppercase', marginBottom:26 }}>◎ What's In The Box</div>
            {[["EYT Pro X Headset","×1"],["USB-C Charging Cable","×1"],["3.5mm Audiophile Cable","×1"],["USB-C Adapter","×1"],["Carry Pouch (Alcantara)","×1"],["Replacement Ear Cushions","×1 Pair"],["Quick Start Guide","×1"]].map(([l,v]) => (
              <div key={l} className="spec-row"><span className="spec-label">{l}</span><span style={{ color:'#555', fontFamily:"'JetBrains Mono',monospace", fontSize:11 }}>{v}</span></div>
            ))}
            <div style={{ marginTop:40 }}>
              <TiltCard style={{ padding:30, border:'1px solid rgba(0,0,0,.08)', borderRadius:4, background:'#fff', position:'relative', overflow:'hidden' }}>
                <div style={{ position:'absolute', top:0, left:0, right:0, height:1, background:'linear-gradient(90deg,transparent,rgba(0,0,0,.2),transparent)' }}/>
                <div style={{ fontFamily:"'Bebas Neue',sans-serif", fontSize:52, color:'#000', letterSpacing:2, lineHeight:1 }}>$349</div>
                <div style={{ fontFamily:"'JetBrains Mono',monospace", fontSize:8, color:'#ccc', letterSpacing:3, textTransform:'uppercase', margin:'6px 0 20px' }}>EYT Pro X · Limited Edition</div>
                <div style={{ display:'flex', gap:10, marginBottom:10 }}>
                  <button className="cta-main" style={{ flex:1 }}><span>Order Now</span></button>
                </div>
                <div style={{ display:'flex', gap:10 }}>
                  <button className="cta-ghost" style={{ flex:1, fontSize:9, letterSpacing:2 }} onClick={() => goTo('sound')}>Hear It First</button>
                  <button className="cta-ghost" style={{ flex:1, fontSize:9, letterSpacing:2 }} onClick={() => goTo('features')}>All Features</button>
                </div>
              </TiltCard>
            </div>
          </div>
        </div>
      </div>

      {/* FOOTER */}
      <footer style={{ padding:'40px 52px 24px', borderTop:'1px solid rgba(0,0,0,.06)', display:'flex', justifyContent:'space-between', alignItems:'center', background:'#fff' }}>
        <div>
          <div style={{ fontFamily:"'Bebas Neue',sans-serif", fontSize:20, color:'#000', letterSpacing:5 }}>EYT</div>
          <div style={{ fontFamily:"'JetBrains Mono',monospace", fontSize:7, color:'#ddd', letterSpacing:3 }}>WIRELESS AUDIO · EST. 2026</div>
        </div>
        <div style={{ fontFamily:"'JetBrains Mono',monospace", fontSize:7, color:'#ddd', letterSpacing:2 }}>© 2026 EYT AUDIO LABS · ALL RIGHTS RESERVED</div>
        <div style={{ display:'flex', gap:22 }}>
          {['Sound','Support','Warranty'].map(l => (
            <span key={l} className="nav-item" style={{ fontSize:8 }} onClick={() => l==='Sound' && goTo('sound')}>{l}</span>
          ))}
        </div>
      </footer>
    </div>
  );
}
